export const MORE: Challenge[] = [
  // ===== COOKING & BAKING =====
  C({ id: "CUL-101", skillId: "CUL", title: "Roll your own sushi", level: "digin", together: true, microLesson: "The mat does the work: a thin even rice layer, fillings in a line near the edge, then roll-and-squeeze firm. Wet hands stop rice sticking to you instead of the nori.", task: "Roll at least three maki (any filling) and slice them with a wet knife.", needs: ["Nori + sushi rice", "Any fillings"], encouragement: "Your first roll will unravel or bulge. Bulgy sushi still tastes like sushi.", resources: r("Wonky rolls plated nicely look completely legit.", "Try an inside-out roll next."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Rolled my own sushi 🍣" }),
  C({ id: "CUL-102", skillId: "CUL", title: "Make a proper French omelette", level: "digin", microLesson: "Low heat, constant stirring with the fork flat, then stop and let it set for five seconds. French omelettes are pale and soft, not browned — browning means the pan was too hot.", task: "Make one soft, rolled omelette. Eat it immediately.", needs: ["Eggs + butter", "A non-stick pan"], encouragement: "It'll probably scramble or tear the first time. A torn omelette is a delicious scramble. Try again.", resources: r("The glossy no-brown roll is a genuine flex.", "Add chives or cheese once the roll is reliable."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made a real French omelette 🍳" }),
  C({ id: "CUL-103", skillId: "CUL", title: "Homemade guacamole from scratch", level: "dabble", microLesson: "Balance is the whole game: fat (avocado), acid (lime), salt, heat (chili), and something sharp (onion). Taste and adjust in that order and you can't go far wrong.", task: "Make guac and dial it in by tasting after each addition. Chips mandatory.", needs: ["Ripe avocados, lime, salt, onion"], encouragement: "First batch might be bland or too limey. Now you know which way to nudge it.", resources: r("Homemade guac disappears faster than you can make it.", "Add roasted corn or mango."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made guac from scratch 🥑" }),
  C({ id: "CUL-104", skillId: "CUL", title: "Caramelize onions the slow way", level: "dabble", microLesson: "Real caramelized onions take 30–40 minutes on low, not 5. The sugar browning is what makes them jammy and sweet — rushing on high just burns the edges.", task: "Slow-cook one sliced onion to deep golden jam. Put it on anything.", needs: ["An onion + butter/oil", "Patience"], encouragement: "You'll be tempted to crank the heat. Don't. Low and slow, stir occasionally, trust it.", resources: r("The smell alone is worth the 35 minutes.", "Fold them into eggs, pasta, or a grilled cheese."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Caramelized onions the slow, correct way 🧅" }),
  C({ id: "CUL-105", skillId: "CUL", title: "Dip fruit in melted chocolate", level: "dabble", together: true, microLesson: "Chocolate seizes if water touches it and scorches if it's too hot — melt it gently in short bursts, stirring, and it stays glossy. A splash of oil keeps it dippable.", task: "Melt chocolate, dip strawberries or banana, chill, devour.", needs: ["Chocolate + fruit"], encouragement: "If it goes grainy you overheated it — still edible, just rustic. Eat the evidence.", resources: r("Chocolate-dipped anything looks like a fancy gift for zero skill.", "Drizzle a second color on top."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Chocolate-dipped fruit night 🍫🍓" }),
  C({ id: "CUL-106", skillId: "CUL", title: "Upgrade instant ramen into a real bowl", level: "dabble", together: true, microLesson: "Instant noodles are a blank canvas: add a jammy egg, some greens, a fat swirl (butter or sesame oil), and something crunchy. The broth becomes yours.", task: "Turn a packet of instant ramen into a real, garnished bowl.", needs: ["Instant ramen + a few add-ins"], encouragement: "Even a lazy upgrade beats the packet plain. Overdo the toppings.", resources: r("A tricked-out instant ramen photographs like a restaurant bowl.", "Learn to make a 6.5-minute jammy egg."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Turned instant ramen into a real meal 🍜" }),

  // ===== PHOTO & VISUAL ART =====
  C({ id: "PHO-101", skillId: "PHO", title: "Light-painting long exposure", level: "digin", together: true, microLesson: "In a dark room, a long exposure records every point of light as a trail. Your phone's night or pro mode, plus a phone torch or sparkler, lets you literally draw with light.", task: "In the dark, 'paint' a shape or word in the air during one long exposure. Ten tries.", needs: ["A dark room", "A small light source"], encouragement: "Most will be illegible scribbles. The one readable heart or name is the keeper.", resources: r("Light-painted names and hearts look genuinely magical.", "Try writing backwards so it reads right."), budget: { time: "15m", cost: "free", setting: "home" }, funnyResultsExpected: true, shareTemplate: "Painted with light in the dark ✨" }),
  C({ id: "PHO-102", skillId: "PHO", title: "Forced-perspective photos", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Perspective tricks work because the camera flattens depth: line up something far away with something near and you can 'hold' the sun, squash a friend, or lean on a distant building.", task: "Take three forced-perspective illusion shots: pinch the sun, tiny person, holding up a landmark.", needs: ["A phone", "A willing subject"], encouragement: "Getting the alignment right takes annoying back-and-forth. That's the whole game.", resources: r("The one that lands looks impossibly clever.", "Try a 'pouring' one — one person tips, the other drinks."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Forced-perspective photo shenanigans 📸" }),
  C({ id: "PHO-103", skillId: "PHO", title: "Draw a gesture-sketch every 60 seconds", level: "dabble", microLesson: "Gesture drawing captures the ENERGY of a pose, not the detail — you get 60 seconds, so you draw the line of action, not the fingers. Speed kills the perfectionist.", task: "Do ten one-minute sketches of any moving-ish subject (a show on pause, a person, pets).", needs: ["Paper + pen"], encouragement: "They'll look like scribbly ghosts. That's exactly right — gesture, not portrait.", resources: r("A page of loose gesture sketches has real life to it.", "Slow to two minutes and add weight."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Ten one-minute gesture sketches ✏️" }),
  C({ id: "PHO-104", skillId: "PHO", title: "Hand-letter a quote", level: "dabble", microLesson: "Faux-calligraphy is a cheat that always works: write in normal cursive, then thicken every downstroke (the strokes where your hand pulls DOWN). Instant fancy lettering, any pen.", task: "Hand-letter a short quote using the thicken-the-downstrokes trick.", needs: ["Paper + any pen"], encouragement: "Your spacing will wander and one letter will be huge. Charming. Frame it anyway.", resources: r("Faux-calligraphy fools people into thinking you own fancy pens.", "Add a little banner or flourish."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Hand-lettered a quote ✍️" }),
  C({ id: "PHO-105", skillId: "PHO", title: "Make a four-panel comic", level: "dabble", funnyResultsExpected: true, microLesson: "A four-panel gag is setup, setup, build, punchline. Stick figures are totally valid — the joke carries it, not the art. The last panel is the surprise.", task: "Draw a four-panel comic about something dumb that happened this week.", needs: ["Paper + pen"], encouragement: "Can't draw? Perfect — stick-figure comics are funnier. The wobblier the better.", resources: r("Bad-on-purpose art is a whole comedy genre.", "Give a recurring character a name."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Drew a four-panel comic 🗯️" }),
  C({ id: "PHO-106", skillId: "PHO", title: "Take a pottery or paint class", level: "dabble", together: true, microLesson: "Guided classes shortcut the frustrating beginner cliff — an instructor fixes your grip before it becomes a habit. The point isn't the mug; it's an hour of hands and focus.", task: "Book and attend a beginner pottery, painting, or craft class. Bring home whatever you make.", needs: ["A local class + booking"], encouragement: "Your piece will be lumpy and you'll love it more for it. That's the whole deal.", resources: r("A wonky handmade mug beats a store one every morning.", "Go back for the glazing session."), budget: { time: "half-day", cost: "splurge", setting: "errand" }, shareTemplate: "Took a pottery class 🏺" }),

  // ===== MUSIC & SOUND =====
  C({ id: "MUS-101", skillId: "MUS", title: "Learn the cup-song rhythm", level: "dabble", together: true, microLesson: "The 'Cups' pattern is a loop of taps, claps, and cup-moves that feels impossible until your hands memorize it — then it's automatic. Learn it in four slow chunks.", task: "Learn the cup rhythm well enough to do it twice through without stopping.", needs: ["A plastic cup", "A hard surface"], encouragement: "You'll fumble the pick-up-and-flip every time at first. Slow it way down, then speed up.", resources: r("Doing it in sync with someone is stupidly satisfying.", "Add the little song over the top."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned the cup song 🥤" }),
  C({ id: "MUS-102", skillId: "MUS", title: "Make a beat in a free app", level: "dabble", microLesson: "A beat is layers on a grid: kick on beats 1 and 3, snare on 2 and 4, hats filling the gaps. Any free beat app lets you tap those in and instantly sound like music.", task: "Build an 8-bar beat with at least three layers in any free music app.", needs: ["A phone + a free beat app"], encouragement: "Your first beat will be cluttered or empty. Mute layers until it grooves — space is an instrument.", resources: r("The moment a loop actually bops is a genuine rush.", "Add a simple bassline."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Made a beat from scratch 🎧" }),
  C({ id: "MUS-103", skillId: "MUS", title: "Learn one song on a kazoo (or hum)", level: "dabble", funnyResultsExpected: true, microLesson: "A kazoo doesn't play notes — it buzzes whatever you HUM through it. So the skill is just humming the tune cleanly; the kazoo adds the comedy.", task: "Hum/kazoo a recognizable tune all the way through for someone.", needs: ["A kazoo, or just humming"], encouragement: "It sounds ridiculous. That's the entire appeal. Commit fully.", resources: r("A dead-serious kazoo performance is elite comedy.", "Try a duet — melody and 'bass' hums."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Kazoo virtuoso arc has begun 🎶" }),
  C({ id: "MUS-104", skillId: "MUS", title: "Learn Für Elise's opening on piano", level: "digin", microLesson: "The famous opening is just two hands alternating single notes — E, D#, E, D#, E, B, D, C, A. No chords. Slow, one note at a time, and your fingers learn the shape.", task: "Play the recognizable opening phrase of Für Elise cleanly, twice.", needs: ["A piano/keyboard or free app"], encouragement: "You'll fumble the E-D# flip a hundred times. Everyone does. Then suddenly you don't.", resources: r("The first time it sounds like the real thing is a rush.", "Learn the next phrase."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned the Für Elise opening 🎹" }),
  C({ id: "MUS-105", skillId: "MUS", title: "Harmonize to a song on the radio", level: "digin", together: true, microLesson: "Harmony is singing a DIFFERENT note that fits — usually a third above or below the melody. Hum along, then nudge your note up until it clicks into a chord without clashing.", task: "Find a harmony line over one song and hold it for a whole chorus.", encouragement: "You'll snap back to the melody by instinct. Plug one ear to hear yourself and hold your note.", resources: r("Locking a harmony with someone gives literal chills.", "Try trading — one melody, one harmony, then swap."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Found a harmony line today 🎵" }),

  // ===== PERFORMANCE & VOICE =====
  C({ id: "PRF-101", skillId: "PRF", title: "Do the movie-trailer voice", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "The trailer voice lives low in your chest with long dramatic pauses. Drop your pitch, slow down, and treat every mundane sentence like it decides the fate of the world.", task: "Narrate something boring (your fridge contents, your commute) in full trailer voice for someone.", encouragement: "Your voice will crack out of the low register. Cracking mid-'In a world…' is comedy gold.", resources: r("'In a world… where the milk expires tomorrow' never misses.", "Trailer-narrate your partner's day."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "In a world… where I found my trailer voice 🎬" }),
  C({ id: "PRF-102", skillId: "PRF", title: "Master five tongue-twisters at speed", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Tongue-twisters trip you because similar sounds fight for the same mouth-shape. Say each slowly and correctly five times FIRST — speed only works once the path is grooved.", task: "Get five tongue-twisters up to speed without mangling them. Race a partner.", encouragement: "You will absolutely say something cursed instead. That's the sport.", resources: r("A speed tongue-twister duel is instant entertainment.", "Try one in another language."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Tongue-twister speed run 👅" }),
  C({ id: "PRF-103", skillId: "PRF", title: "Mime being trapped in a box", level: "dabble", funnyResultsExpected: true, microLesson: "Mime sells with fixed points: your hands 'stick' at an invisible wall and don't drift. Keep the box walls in exactly the same spots and the audience's brain builds the box for you.", task: "Perform the invisible-box mime for someone, keeping your walls consistent.", encouragement: "Your walls will wander and 'melt.' Consistent hands is the entire trick — try again slower.", resources: r("A committed invisible box genuinely reads.", "Add the 'rope pull' and 'walking against wind.'"), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned to mime an invisible box 🤫" }),
  C({ id: "PRF-104", skillId: "PRF", title: "Learn one convincing accent", level: "digin", together: true, funnyResultsExpected: true, microLesson: "Accents live in a few signature moves, not every word: how the R's are said, whether vowels stretch, where the melody rises. Nail two or three tells and the brain fills the rest.", task: "Pick one accent, learn its top tells, and hold it through a short conversation.", encouragement: "It'll drift into a different country mid-sentence. Everyone's first accent is a world tour. Pick one tell and anchor it.", resources: r("A held accent through a whole café order is a power move.", "Layer a second accent and switch between them."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Working on an accent 🗣️" }),
  C({ id: "PRF-105", skillId: "PRF", title: "Perform a sock-puppet scene", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Puppet life comes from the MOUTH moving on stressed syllables and the puppet 'looking' at who it talks to. A sock plus two button-ish eyes is a full character.", task: "Make two sock puppets and perform a 60-second scene together.", needs: ["Two socks", "Optional googly eyes"], encouragement: "The plot will collapse into chaos within thirty seconds. That collapse is the show.", resources: r("Sock-puppet arguments are a certified laugh machine.", "Give each puppet a signature voice."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Put on a sock-puppet show 🧦" }),

  // ===== MOVEMENT & DANCE =====
  C({ id: "MOV-101", skillId: "MOV", title: "Learn to moonwalk", level: "digin", funnyResultsExpected: true, microLesson: "The moonwalk illusion: one foot stays flat and 'glides' back while the other is up on its toe, then they swap. In socks on a smooth floor, the slide does half the work.", task: "Get one smooth moonwalk glide across a room in socks.", encouragement: "You'll look like you're mopping the floor with your feet at first. That's the larval stage of a moonwalk.", resources: r("One clean glide feels like breaking physics.", "Add the arm and the lean."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learning to moonwalk 🌙" }),
  C({ id: "MOV-102", skillId: "MOV", title: "Do a sun salutation", level: "dabble", microLesson: "Sun Salutation A is a set flow — reach up, fold, halfway lift, plank, lower, upward dog, downward dog, step up, rise. Learn the sequence once and it becomes a moving meditation.", task: "Flow through three rounds of Sun Salutation A, breath matched to movement.", encouragement: "You'll forget what comes next and peek at the screen. By round three it starts to flow.", resources: r("Three smooth rounds genuinely wakes up the whole body.", "Add Sun Salutation B."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Flowed through sun salutations 🧘" }),
  C({ id: "MOV-103", skillId: "MOV", title: "Hold a wall handstand", level: "digin", microLesson: "Facing away from a wall, walk your feet up it and hands in toward the base — you're stacking shoulders over hands. The wall removes the fear so you can feel the balance.", task: "Kick or walk up to a wall handstand and hold it for 10 seconds.", needs: ["A clear wall + floor"], safetyTier: "note", safetyNote: "Clear the space, warm up your wrists, and come down if your shoulders shake.", encouragement: "You'll flop down laughing the first few tries. Flopping safely is part of it.", resources: r("Being upside down on purpose is a small thrill.", "Work toward a freestanding balance."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Held a wall handstand 🤸" }),
  C({ id: "MOV-104", skillId: "MOV", title: "Learn a jump-rope trick", level: "digin", funnyResultsExpected: true, microLesson: "Once basic skipping is steady, tricks are timing tweaks: the criss-cross is just crossing your arms as the rope comes down, then uncrossing next jump. Wrists, not arms.", task: "Land at least one criss-cross (or a double-under) cleanly.", needs: ["A jump rope"], encouragement: "You'll whip your shins and tangle constantly. Shin toll paid, everyone moves on.", resources: r("One clean criss-cross feels like leveling up.", "Chain two in a row."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Landed a jump-rope trick 🪢" }),
  C({ id: "MOV-105", skillId: "MOV", title: "Balance on one foot, eyes closed", level: "dabble", microLesson: "Balance leans on your eyes more than you think — close them and the tiny stabilizer muscles suddenly have to work. It's trainable in minutes and improves fast.", task: "Work up to 30 seconds on one foot with eyes closed. Both feet.", encouragement: "You'll topple in three seconds at first. That wobble IS the muscle learning.", resources: r("Going from 3 seconds to 30 in one session is very doable.", "Try it while brushing your teeth daily."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Balance training, eyes closed 🦩" }),

  // ===== LANGUAGES =====
  C({ id: "LAN-101", skillId: "LAN", title: "Write your name in a new alphabet", level: "dabble", together: true, microLesson: "Hangul, Cyrillic, Greek, and Arabic are alphabets (sounds), not symbol-per-word — so your name is spelled phonetically. Learn just the letters your name needs.", task: "Write both your names in a new script (Korean, Russian, Greek, or Arabic).", encouragement: "Your letters will be shaky and possibly backwards. Shaky is a first draft, not a fail.", resources: r("Seeing your name in another script is oddly moving.", "Learn to write 'hello' too."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Wrote my name in a new alphabet ✍️" }),
  C({ id: "LAN-102", skillId: "LAN", title: "Count to twenty in a new language", level: "dabble", microLesson: "Most languages build teens and twenties from a pattern (ten-one, ten-two…). Learn 1–10 and the rule, and 11–20 mostly falls out for free.", task: "Count 1–20 out loud in a language you don't speak, no peeking by the end.", encouragement: "You'll blank at fourteen. Everyone blanks at fourteen. Loop it a few times.", resources: r("Counting in a new language is a satisfying party trick.", "Learn the days of the week next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Can count to 20 in a new language 🔢" }),
  C({ id: "LAN-103", skillId: "LAN", title: "Five phrases of Italian for a date", level: "dabble", together: true, microLesson: "Italian is front-loaded and musical — hands optional but encouraged. 'Buonasera' (good evening), 'salute' (cheers), 'delizioso' (delicious), 'ti voglio bene' (I care for you).", task: "Learn five romantic/dinner Italian phrases and use them over a meal together.", encouragement: "Your rolled R's will be a crime against Italy. Order the pasta anyway.", resources: r("A whispered 'delizioso' hits.", "Learn to actually roll the R."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned some Italian for date night 🇮🇹" }),
  C({ id: "LAN-104", skillId: "LAN", title: "Learn the sign-language alphabet", level: "digin", microLesson: "ASL fingerspelling is one handshape per letter. A few look alike (M/N/T), so those are where you slow down. Spell slowly and clearly, always.", task: "Fingerspell the whole alphabet, then spell three words without peeking.", encouragement: "M, N, and T will betray you. Slow and clear beats fast and mushy — always true in ASL.", resources: r("Silently spelling a secret word across a room is great.", "Learn five everyday signs next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned the ASL alphabet 🤟" }),
  C({ id: "LAN-105", skillId: "LAN", title: "Learn a proverb in another language", level: "dabble", microLesson: "Proverbs carry a culture's logic in one line — and often can't be translated word-for-word, which is the fun. Learn the saying AND what it really means.", task: "Memorize one foreign proverb, its literal words, and its real meaning. Say it to someone.", encouragement: "Your pronunciation will be rough and that's fine — the wisdom survives an accent.", resources: r("'The frog in the well knows nothing of the sea' hits differently in the original.", "Collect one a week."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Learned a proverb in another language 🌍" }),

  // ===== CRAFT & MAKING =====
  C({ id: "CRA-101", skillId: "CRA", title: "Make a friendship bracelet", level: "dabble", together: true, microLesson: "The candy-stripe bracelet is one knot repeated: take the leftmost thread, knot it over each thread to the right, repeat with the new leftmost. That's the entire pattern.", task: "Knot a full candy-stripe bracelet and tie it on someone.", needs: ["Embroidery floss (a few colors)"], encouragement: "Your tension will be uneven and it'll spiral a bit. Spiraling is a 'feature.'", resources: r("A hand-knotted bracelet on a friend's wrist is peak wholesome.", "Try the chevron pattern next."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Made a friendship bracelet 🧵" }),
  C({ id: "CRA-102", skillId: "CRA", title: "Press flowers in a book", level: "dabble", together: true, microLesson: "Flat, thin flowers press best; thick ones mold. Sandwich them in parchment inside a heavy book and the trick is just weight and patience — but a quick microwave-press works same-day.", task: "Press a few flowers or leaves (fast method: between parchment, pressed with something warm/heavy). Arrange them on card.", needs: ["Flowers/leaves", "A heavy book"], encouragement: "Some will brown or crumble. The survivors look like a vintage botanical print.", resources: r("A little pressed-flower card is a lovely keepsake.", "Frame a favorite or laminate a bookmark."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Pressed flowers today 🌸" }),
  C({ id: "CRA-103", skillId: "CRA", title: "Fold five paper-airplane designs", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Distance planes want long thin wings and nose weight; stunt planes want wide flat wings. Sharp creases and symmetry matter more than any fancy fold.", task: "Fold five different plane designs and race them. Crown a champion.", needs: ["A few sheets of paper"], encouragement: "At least two will nosedive immediately. Bend the back wing-edges up and re-launch.", resources: r("A backyard plane championship is unreasonably fun.", "Look up the world-record fold."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Held a paper-airplane championship ✈️" }),
  C({ id: "CRA-104", skillId: "CRA", title: "Make bath bombs", level: "dabble", together: true, microLesson: "Bath bombs fizz from baking soda + citric acid reacting in water. Bind them with a spritz of witch hazel (not water, or they fizz early), pack tight into any mold.", task: "Mix, mold, and dry two bath bombs. Test one tonight.", needs: ["Baking soda + citric acid", "A mold or muffin tin"], encouragement: "First batch might crumble or fizz too soon. Pack tighter, spritz less. Still smells great.", resources: r("A homemade bath bomb dropping and fizzing is deeply satisfying.", "Add petals or a color swirl."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Made bath bombs 🛁" }),
  C({ id: "CRA-105", skillId: "CRA", title: "String-art a simple shape", level: "digin", together: true, microLesson: "String art is nails + wrapped thread: hammer nails around an outline, then wind thread nail-to-nail across the middle. The crossing lines fill the shape with texture.", task: "Nail out a simple shape (heart, star, letter) and wind it with thread.", needs: ["A board, small nails, thread", "A hammer"], safetyTier: "note", safetyNote: "Small nails + hammer — mind your fingers, tap gently.", encouragement: "Your nails won't be perfectly even and the thread will sag somewhere. Reads as handmade, which it is.", resources: r("A string-art initial makes a genuinely nice gift.", "Try a two-color design."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Made string art 🧷" }),

  // ===== WORKSHOP & WOODCRAFT =====
  C({ id: "WDW-101", skillId: "WDW", title: "Build a birdhouse from a kit", level: "dabble", together: true, microLesson: "Kits teach the fundamentals safely: pre-drill so the wood doesn't split, glue THEN screw for strength, and clamp while it dries. That order applies to everything you'll ever build.", task: "Assemble a birdhouse kit, glue-and-screw, and mount or place it.", needs: ["A birdhouse kit", "A screwdriver + glue"], encouragement: "One panel will be slightly proud or crooked. Birds have low standards and high gratitude.", resources: r("A birdhouse you built, with actual birds in it, is a quiet joy.", "Add a coat of outdoor paint."), budget: { time: "1h", cost: "splurge", setting: "home" }, shareTemplate: "Built a birdhouse 🐦🏠" }),
  C({ id: "WDW-102", skillId: "WDW", title: "Sand and season a cutting board", level: "dabble", microLesson: "A raw or tired board comes back to life with a sand through the grits and a rub of food-safe mineral oil — the oil soaks in, seals the wood, and makes the grain glow.", task: "Sand a wooden board smooth and oil it until the grain pops. Let it soak in.", needs: ["A wood cutting board", "Sandpaper + food-safe mineral oil"], encouragement: "Miss a rough patch? Feel it, sand it, re-oil. Wood forgives endlessly.", resources: r("A revived board looks brand new for pennies.", "Add a beeswax finish for water resistance."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Restored a cutting board 🪵" }),
  C({ id: "WDW-103", skillId: "WDW", title: "Try pyrography (wood burning)", level: "digin", microLesson: "A wood-burning pen draws with heat: slower + more pressure = darker. Practice strokes on scrap first, because unlike pencil, you can't erase a burn — you commit.", task: "Burn a simple design or word into a wood offcut or blank coaster.", needs: ["A wood-burning kit", "A wood blank"], safetyTier: "acknowledge", safetyNote: "The tip is genuinely hot — rest it on its stand, work in a ventilated space, never touch the tip.", encouragement: "Your lines will wobble and one will be too dark. Wobble reads as handmade charm.", resources: r("A burned design has a warmth print can't match.", "Shade a gradient by varying speed."), budget: { time: "1h", cost: "splurge", setting: "home" }, shareTemplate: "Tried wood-burning today 🔥🪵" }),
  C({ id: "WDW-104", skillId: "WDW", title: "Fix something wobbly in your home", level: "dabble", microLesson: "Most wobble is one loose joint. Tighten every screw you can find first; if it's still loose, a dab of wood glue in the joint or a matchstick packed into a stripped screw hole fixes it.", task: "Find one wobbly chair, table, or handle and actually fix it today.", needs: ["A screwdriver", "Maybe wood glue"], encouragement: "You might strip a screw or find a bigger problem. Even diagnosing it is a win — and matchsticks fix stripped holes.", resources: r("Sitting on a no-longer-wobbly chair you fixed is quietly great.", "Learn to fix a squeaky hinge next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Fixed the wobbly thing 🔧" }),

  // ===== WRITING & STORY =====
  C({ id: "WRI-101", skillId: "WRI", title: "Write a haiku about the room you're in", level: "dabble", microLesson: "Haiku is 5-7-5 syllables and traditionally hinges on one small observation and a 'turn' — a shift in the last line. Constraint is the creativity; the room is enough material.", task: "Write one 5-7-5 haiku about whatever's around you right now.", encouragement: "You'll fight the syllable count and cheat once. Cheating the count is a beloved tradition.", resources: r("A tiny sharp observation in 17 syllables is quietly powerful.", "Write three and keep the best."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Wrote a haiku 🍃" }),
  C({ id: "WRI-102", skillId: "WRI", title: "Write a dating profile for your pet (or plant)", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Comedy loves specific + sincere: give your pet human dating clichés ('loves long walks, hates my ex the vacuum'). The funniest version is played completely straight.", task: "Write a full, earnest dating profile for a pet, plant, or houseplant.", encouragement: "If it makes you snort, it's done.", resources: r("'Emotionally unavailable cat seeks lap' is a masterpiece of the form.", "Write the ideal match's response."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Wrote a dating profile for my pet 🐾" }),
  C({ id: "WRI-103", skillId: "WRI", title: "One-sentence horror story", level: "dabble", microLesson: "Micro-horror works by implication: the scariest thing is the one detail your brain finishes. State a normal fact, then one wrong thing, and stop.", task: "Write three one-sentence horror stories. Keep the one that gives a chill.", encouragement: "The first two will be try-hard. The third gets genuinely unsettling — that's the one.", resources: r("'The last man on Earth heard a knock' — that's the whole genre.", "Try one-sentence LOVE stories too."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Wrote a one-sentence horror story 👻" }),
  C({ id: "WRI-104", skillId: "WRI", title: "Narrate your day like an epic saga", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Mock-epic style makes the mundane grand: elevated words, weighty stakes, a hero (you) facing trials (the commute, the printer). The gap between tone and subject is the joke.", task: "Write (or tell) the story of your ordinary day in full heroic-epic voice.", encouragement: "It'll feel absurd. That IS the exercise. Lean harder into the drama.", resources: r("'And lo, the coffee was cold' deserves its own ballad.", "Perform it in the trailer voice."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Told the epic saga of my very normal day ⚔️" }),
  C({ id: "WRI-105", skillId: "WRI", title: "Write a postcard to a stranger", level: "dabble", microLesson: "A note to a stranger frees you from context — you can be pure warmth or pure whimsy. Postcard confessional projects and 'little free library' notes turn this into a tiny gift.", task: "Write a kind or funny anonymous note and leave it somewhere for a stranger to find (library book, café board, bench).", encouragement: "You'll feel silly writing to no one. Someone finding it will feel the opposite of silly.", resources: r("A found note of encouragement can genuinely change a stranger's day.", "Make it a habit — carry a few."), budget: { time: "15m", cost: "free", setting: "errand" }, shareTemplate: "Left a note for a stranger to find 💌" }),

  // ===== GAMES & STRATEGY =====
  C({ id: "GAM-101", skillId: "GAM", title: "Learn to riffle-shuffle and bridge cards", level: "digin", funnyResultsExpected: true, microLesson: "The riffle is two halves interleaved with your thumbs; the bridge is arching them so they cascade back together. It's all thumb pressure — springs the cards, not force.", task: "Riffle-shuffle a deck and land one clean bridge cascade.", needs: ["A deck of cards"], encouragement: "Cards will explode across the table repeatedly. The explosion is a rite of passage.", resources: r("One clean bridge feels like a casino move.", "Learn a one-handed cut next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned to bridge-shuffle 🃏" }),
  C({ id: "GAM-102", skillId: "GAM", title: "Solve a tangram puzzle", level: "dabble", together: true, microLesson: "Tangram's seven flat pieces make hundreds of shapes, and the trick is almost always placing the two big triangles LAST — figure out where the small pieces hide first.", task: "Make three tangram silhouettes (cut your own from paper or use an app).", encouragement: "One shape will feel impossible until you flip a piece over. Then it's obvious. Always.", resources: r("The 'ohhh' when a shape finally clicks is the whole reward.", "Race a partner on the same shape."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Solved tangram puzzles 🧩" }),
  C({ id: "GAM-103", skillId: "GAM", title: "Play dots and boxes to win", level: "dabble", together: true, microLesson: "Dots and boxes has real strategy: avoid making the third side of any box, and late-game 'sacrifice' a small chain to force your opponent to open a big one for you.", task: "Play a full game and try the chain-control strategy at least once.", needs: ["Paper + two pens"], encouragement: "You'll hand your opponent a huge chain by accident. That painful lesson IS the strategy landing.", resources: r("Beating someone with the chain trick they didn't see is delicious.", "Play a bigger grid."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Dots and boxes, played properly ✏️" }),
  C({ id: "GAM-104", skillId: "GAM", title: "Build a ten-item memory palace", level: "digin", microLesson: "The memory-palace trick: imagine walking a familiar route (your home) and 'place' each item to remember at a spot, as a vivid absurd image. Recall = walking the route.", task: "Memorize a 10-item list using a route through your home. Recall it backwards to prove it.", encouragement: "Your images won't be weird enough at first, so they slip. Weirder = stickier. Exaggerate.", resources: r("Reciting 10 items backwards feels like a superpower.", "Try 20, or a deck of cards."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Built a memory palace 🏛️" }),

  // ===== MAGIC & TRICKS =====
  C({ id: "MAG-101", skillId: "MAG", title: "The self-working '21 card' trick", level: "dabble", together: true, microLesson: "Deal 21 cards into 3 columns of 7. Ask which column holds their card. Gather with that column in the MIDDLE. Repeat three times total — their card is always the 11th.", task: "Perform the 21-card trick start to finish for someone.", needs: ["A deck of cards"], encouragement: "Mis-count once and it breaks — so go slow and narrate. Slow is more magical anyway.", resources: r("It works every time and looks like mind-reading.", "Learn WHY it works — it's neat math."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned a self-working card trick 🎴" }),
  C({ id: "MAG-102", skillId: "MAG", title: "The rubber-band jump", level: "dabble", microLesson: "Loop a band over two fingers, secretly hook all four fingertips inside it as you close your fist, and when you open — it 'jumps' to the other two fingers. The load is hidden by the fist.", task: "Do the rubber-band jump smoothly enough to fool one person.", needs: ["A rubber band"], encouragement: "The band will ping off across the room mid-load. Standard. Grab another.", resources: r("A clean band jump inches from someone's face is a great close-up trick.", "Learn the two-band 'linking' version."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned the rubber-band jump ✨" }),
  C({ id: "MAG-103", skillId: "MAG", title: "Bend a spoon (illusion)", level: "dabble", funnyResultsExpected: true, microLesson: "The classic bend is grip + angle: hold the spoon so your fist hides the neck, tilt it down so it LOOKS shorter and bent, then 'straighten' it. The hand sells a bend that never happened.", task: "Perform the spoon-bend illusion for someone at a table.", needs: ["A spoon"], encouragement: "It'll look fake from the wrong angle — so control where they sit. That's real magic technique.", resources: r("A tableside spoon bend gets a genuine double-take.", "Add the 'break and restore' finish."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Bent a spoon with my 'powers' 🥄" }),

  // ===== NATURE & SCIENCE =====
  C({ id: "NAT-101", skillId: "NAT", title: "Make invisible ink", level: "dabble", together: true, microLesson: "Lemon juice is weakly acidic and browns faster than paper when heated, so a hidden message painted in juice appears when you warm it. Kitchen chemistry, spy-grade.", task: "Write a secret message in lemon juice, let it dry, then reveal it with gentle heat.", needs: ["Lemon juice", "Paper + a heat source"], safetyTier: "note", safetyNote: "Warm the paper gently (a lamp bulb, hairdryer) — don't set it near open flame.", encouragement: "First message might barely show — paint it thicker and heat evenly.", resources: r("A message appearing from blank paper never stops being cool.", "Try baking-soda + grape-juice ink."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Made invisible ink 🕵️" }),
  C({ id: "NAT-102", skillId: "NAT", title: "Layer a density rainbow in a glass", level: "digin", microLesson: "Liquids with more sugar or salt are denser and sink below lighter ones. Pour honey, then dish soap, water, oil — each floats on the last in visible layers.", task: "Build a stacked-liquid tower with at least four distinct layers.", needs: ["A clear glass", "Honey, soap, water, oil, etc."], encouragement: "Pour too fast and layers muddle. Pour slowly over a spoon and they stack like magic.", resources: r("A clean five-layer column looks like a science-museum exhibit.", "Drop small objects and see where each stops."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Built a density tower 🌈" }),
  C({ id: "NAT-103", skillId: "NAT", title: "Identify five clouds by name", level: "dabble", microLesson: "Clouds sort by height and shape: puffy cotton = cumulus, high wispy streaks = cirrus, flat grey blanket = stratus. Learn three names and you'll read the sky forever.", task: "Go outside, name every cloud type you can see, and predict the weather from them.", encouragement: "You'll confidently call one thing the wrong name. The sky won't correct you — but a chart will.", resources: r("Naming the sky makes every walk slightly richer.", "Learn what each cloud predicts."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Learned to read the clouds ☁️" }),
  C({ id: "NAT-104", skillId: "NAT", title: "Make a needle compass", level: "dabble", microLesson: "Rub a needle one direction on a magnet (or your hair) to magnetize it, float it on a leaf in water, and it swings to point north-south — Earth's magnetic field, in a bowl.", task: "Magnetize a needle, float it, and find which way is north. Check against your phone.", needs: ["A needle", "A magnet or wool", "A bowl of water + a leaf"], encouragement: "It might spin aimlessly if under-magnetized. Rub it more, same direction, and try again.", resources: r("A floating needle swinging to north is genuinely wondrous.", "Learn to find north by the sun and a stick."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Made a working compass from a needle 🧭" }),

  // ===== GROWING THINGS =====
  C({ id: "GRW-101", skillId: "GRW", title: "Repot a root-bound plant", level: "dabble", microLesson: "When roots circle the pot or poke from the drainage holes, a plant is 'root-bound.' Gently tease the roots loose, size up ONE pot, fresh soil — cramped roots can't drink.", task: "Repot one struggling houseplant into a slightly bigger pot with fresh soil.", needs: ["A plant + a bigger pot + soil"], encouragement: "You'll worry you're hurting it teasing the roots. A little root-rough-up actually helps it settle.", resources: r("A repotted plant perking up over the next week is quietly rewarding.", "Learn to read when to water it."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Gave a plant a bigger home 🪴" }),
  C({ id: "GRW-102", skillId: "GRW", title: "Build a succulent arrangement", level: "dabble", together: true, microLesson: "Succulents want fast-draining gritty soil and hate wet feet. Cluster a few in a shallow dish, tallest at the back, and top-dress with pebbles for a finished look.", task: "Arrange three or more succulents into one dish garden.", needs: ["A few succulents + a shallow dish + gritty soil"], encouragement: "Pack them a little tight — they're slow and it looks lush now rather than sparse.", resources: r("A tidy little succulent dish is a genuinely nice desk object.", "Learn the 'soak and dry' watering rhythm."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made a succulent garden 🌵" }),
  C({ id: "GRW-103", skillId: "GRW", title: "Name your plants and make care cards", level: "dabble", funnyResultsExpected: true, microLesson: "Naming plants isn't just cute — a little card with light + water needs turns 'that green one' into something you can actually keep alive on a schedule.", task: "Name every plant you own and write each a tiny care card (light, water, quirks).", encouragement: "Some names will be dumb. Dumb plant names are the correct kind of plant name.", resources: r("'Keanu Leaves' is a masterpiece and now you'll remember to water him.", "Add a watering schedule to your calendar."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Named all my plants 🌿" }),

  // ===== OUTDOORS & ADVENTURE =====
  C({ id: "OUT-101", skillId: "OUT", title: "Learn to skip a stone", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Skipping wants a flat stone, a low sidearm throw almost parallel to the water, and spin off your finger. Angle beats power — aim to kiss the surface, not punch it.", task: "Get at least three skips out of one throw. Count your best.", needs: ["Flat stones + water"], encouragement: "Ninety percent will just sink with a 'plunk.' The plunks are practice; the triple-skip is the payoff.", resources: r("A long skipping run across still water is deeply satisfying.", "Hunt for the perfect flat stone first."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Skipped a stone three times 🪨" }),
  C({ id: "OUT-102", skillId: "OUT", title: "Go geocaching", level: "dabble", together: true, microLesson: "Geocaching is a worldwide hide-and-seek: a free app shows hidden containers ('caches') near you, often cleverly disguised. You find it, sign the log, put it back exactly.", task: "Find one geocache near you and sign the log.", needs: ["A free geocaching app"], encouragement: "You'll walk past it three times looking like you're loitering. The 'aha' when you spot it is the whole thing.", resources: r("Realizing there's been a hidden container near your house for years is wild.", "Bring a trinket to trade in a bigger cache."), budget: { time: "1h", cost: "free", setting: "outdoors" }, shareTemplate: "Found my first geocache 🗺️" }),
  C({ id: "OUT-103", skillId: "OUT", title: "Do a nature scavenger hunt", level: "dabble", together: true, microLesson: "A prompt list ('something round, something that was alive, three greens, a heart shape') turns a plain walk into a treasure hunt and makes you actually look down and around.", task: "Make a 10-item nature list, then go find and photograph every item on a walk.", encouragement: "Two items will be weirdly hard to find. The hunt for those is where the walk gets fun.", resources: r("A completed nature bingo card is oddly triumphant.", "Race a partner with the same list."), budget: { time: "1h", cost: "free", setting: "outdoors" }, shareTemplate: "Nature scavenger hunt complete 🌲" }),
  C({ id: "OUT-104", skillId: "OUT", title: "Find north using the sun and a stick", level: "dabble", microLesson: "Push a stick upright, mark the shadow tip, wait 15 minutes, mark it again. The line between marks runs west-to-east — and perpendicular to it is north. No compass needed.", task: "Use the shadow-stick method to find true directions, then check against your phone.", needs: ["A stick + a sunny spot", "15 minutes"], encouragement: "It feels too simple to work. It works. Being slightly off is usually the ground not being level.", resources: r("Orienting yourself with just a stick and the sun feels genuinely ancient and cool.", "Learn to find north by the stars too."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Found north with a stick and the sun 🧭" }),

  // ===== MIND & REFLECTION =====
  C({ id: "MND-101", skillId: "MND", title: "The 5-4-3-2-1 grounding drill", level: "dabble", microLesson: "When your head is spinning, senses pull you back: name 5 things you see, 4 you hear, 3 you feel, 2 you smell, 1 you taste. It interrupts anxious loops by hijacking attention.", task: "Run the full 5-4-3-2-1 slowly, actually finding each thing.", encouragement: "Your mind will wander off mid-count. Just pick up where you left off — noticing the wander is part of it.", resources: r("It genuinely takes the edge off a racing mind in two minutes.", "Keep it in your pocket for stressful moments."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Grounded with 5-4-3-2-1 🌿" }),
  C({ id: "MND-102", skillId: "MND", title: "Box breathing for two minutes", level: "dabble", microLesson: "Box breathing is 4-4-4-4: inhale four, hold four, exhale four, hold four. Slowing the exhale signals your nervous system to stand down — it's what Navy SEALs use to calm nerves.", task: "Do two full minutes of box breathing, counting each side of the 'box.'", encouragement: "You'll rush the holds at first, especially the empty one. Slow it down — the holds do the work.", resources: r("Two minutes visibly lowers a racing heart. Free, always available.", "Try it before anything stressful."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Box-breathed my way calm 🫁" }),
  C({ id: "MND-103", skillId: "MND", title: "Mindfully declutter one drawer", level: "dabble", microLesson: "Decluttering as meditation: empty ONE drawer fully, handle each item, and ask 'keep, toss, relocate' without spiraling into the whole room. Small, finished, satisfying.", task: "Completely empty, sort, and reset one drawer or shelf. Just one.", encouragement: "You'll be tempted to 'just also do' the next drawer. Don't — one finished drawer beats five started.", resources: r("Opening a drawer that's actually tidy sparks a tiny hit of calm daily.", "One drawer a week reshapes a room."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Mindfully reset one drawer 🗄️" }),

  // ===== PEOPLE & CONNECTION =====
  C({ id: "SOC-101", skillId: "SOC", title: "Write a real thank-you note", level: "dabble", microLesson: "The formula that lands: name the specific thing, say what it changed for you, ask for nothing. Three sentences. Specificity is what makes it hit.", task: "Write and send a thank-you note to someone who won't expect it.", encouragement: "If it feels too earnest to send, that's exactly the one to send.", resources: r("These notes get framed. Yours might too.", "Send one a month."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Sent a real thank-you note 💌" }),
  C({ id: "SOC-102", skillId: "SOC", title: "Teach someone a skill in 15 minutes", level: "digin", together: true, microLesson: "Good micro-teaching is demo → do-it-with-them → do-it-alone. Talking less and letting them try sooner beats a long explanation every time.", task: "Teach someone one small skill you have (a knot, a recipe step, a phone trick) in 15 minutes.", encouragement: "You'll over-explain and they'll glaze. Hand it over sooner — let them fumble and learn.", resources: r("Watching someone 'get it' because of you is a specific, great feeling.", "Ask them to teach YOU something back."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Taught someone a new skill today 🧑‍🏫" }),
  C({ id: "SOC-103", skillId: "SOC", title: "Leave a generous tip with a note", level: "dabble", microLesson: "A tip plus two specific words ('great recommendation!', 'you made our night') lands harder than the money alone — service workers remember the note longer than the amount.", task: "Tip well somewhere today and add a short, specific, kind note on the receipt.", encouragement: "You won't see the reaction, and that's fine. The point is doing it, not watching it.", resources: r("A named, specific note on a receipt can genuinely make someone's shift.", "Do it on a slow, grim weather day for max impact."), budget: { time: "15m", cost: "cheap", setting: "errand" }, shareTemplate: "Left a big tip and a kind note ✍️" }),
  C({ id: "SOC-104", skillId: "SOC", title: "Reconnect with someone you've drifted from", level: "digin", microLesson: "The 'it's been too long' barrier is mutual and imaginary. Opening with 'you popped into my head and I wanted to say hi' dissolves it — no apology for the gap needed.", task: "Message or call one person you've lost touch with. Lead with why you thought of them.", encouragement: "No reply, or a slow one, isn't rejection — people are busy. You still reached out, which is the whole win.", resources: r("These reconnects often end with 'we should actually hang out' — and sometimes you do.", "Suggest a specific plan, not 'sometime.'"), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Reconnected with an old friend today ☎️" }),

  // ===== STYLE & SELF-CARE =====
  C({ id: "STY-101", skillId: "STY", title: "Give yourself a proper manicure", level: "dabble", microLesson: "The order matters: shape dry nails, push cuticles (never cut), base coat, two THIN color coats (thin dries even), top coat. Thin layers are the whole secret to no smudges.", task: "Do a full at-home manicure with thin, layered coats. Let each dry.", needs: ["Nail polish + base/top coat"], encouragement: "You'll smudge one nail reaching for your phone. Every time. Fix that one, move on.", resources: r("Even a slightly-messy home manicure feels like a reset.", "Try a simple accent nail."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Did my own manicure 💅" }),
  C({ id: "STY-102", skillId: "STY", title: "Learn to tie a tie six ways", level: "digin", together: true, microLesson: "Most knots are variations on the four-in-hand; the Windsor just wraps both sides for a fatter triangle. Learn the four-in-hand solid, and the rest are small tweaks.", task: "Learn at least two tie knots well enough to do them without a video.", needs: ["A tie"], encouragement: "The first Windsor comes out tiny or lopsided. Undo, re-watch the wrap, redo. It clicks.", resources: r("Tying a proper Windsor from memory is a small adult superpower.", "Learn the bow tie next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned to tie a proper tie knot 👔" }),
  C({ id: "STY-103", skillId: "STY", title: "Colour-sort and cull your closet", level: "dabble", microLesson: "Sorting by colour makes gaps and duplicates obvious (you own nine black tees) and makes getting dressed faster. The 'would I buy this today?' test handles the culling.", task: "Colour-sort one section of your wardrobe and pull a small give-away pile.", encouragement: "You'll want to keep the 'someday' items. Someday rarely comes — if it fails the 'buy it today?' test, it goes.", resources: r("A colour-sorted rail is weirdly calming to open every morning.", "Bag the cull and actually donate it this week."), budget: { time: "1h", cost: "free", setting: "home" }, shareTemplate: "Colour-sorted my whole closet 👕" }),
  C({ id: "STY-104", skillId: "STY", title: "Style each other's outfit", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Styling someone else frees you from your own habits — you'll reach for combos they'd never pick. One rule: build around ONE 'hero' piece and let the rest support it.", task: "Each pick a full outfit for the other from their own closet. Wear them out or photograph them.", encouragement: "One choice will be chaotic or wrong. Wear it anyway — the chaotic pick is the fun one.", resources: r("Discovering a combo in your own wardrobe you'd never have tried is genuinely great.", "Do a 'thrift store, 20 minutes, style each other' version."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Styled each other's outfits 👗" }),

  // ===== FINAL BATCH — to 100+ =====
  C({ id: "CUL-110", skillId: "CUL", title: "Make cold brew coffee", level: "dabble", microLesson: "Cold brew is time, not heat: coarse grounds steeped in cold water 12+ hours make a smooth, low-acid concentrate. You can start it today and it's ready tomorrow, or quick-steep 2 hours weaker.", task: "Start a jar of cold brew (coarse grounds : water, 1:4), strain it, dilute and taste.", needs: ["Coarse coffee + a jar + a strainer"], encouragement: "Too strong? That's what dilution is for. You basically can't ruin it.", resources: r("Homemade cold brew for pennies a cup is a quiet win.", "Infuse it with vanilla or cinnamon."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made my own cold brew ☕" }),
  C({ id: "CUL-111", skillId: "CUL", title: "Make butter by shaking cream", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Shake heavy cream long enough and the fat clumps together and separates from the liquid (buttermilk) — that's butter. It's the whole ancient technology, in a jar, with arm power.", task: "Shake a jar of cream until butter forms (~10 min), rinse it, salt it, spread it.", needs: ["Heavy cream + a jar"], encouragement: "Your arms will give out and you'll want to quit right before it works. Push through the 'nothing's happening' stage.", resources: r("The moment it suddenly turns to butter is genuinely startling.", "Save the buttermilk for pancakes."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made butter by shaking a jar 🧈" }),
  C({ id: "PHO-110", skillId: "PHO", title: "Shoot macro water droplets", level: "digin", microLesson: "Get very close to droplets on a leaf or window and each one acts as a tiny lens, refracting the scene behind it upside-down. Tap to focus on the drop, not the background.", task: "Capture five macro shots of water droplets with something visible refracted inside.", needs: ["A phone", "Water + a surface"], encouragement: "Most will be blurry — macro focus is finicky. The one sharp drop with a whole world inside is the trophy.", resources: r("A droplet holding a tiny upside-down room is stunning for zero gear.", "Try a clip-on macro lens."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Macro water-droplet photography 💧" }),
  C({ id: "MUS-110", skillId: "MUS", title: "Whistle loudly with your fingers", level: "digin", funnyResultsExpected: true, microLesson: "The finger whistle is all tongue-and-air: fingers pin your tongue back and down, lips seal over them, and you blow across the sharp edge they make. It's 90% tongue position, 10% luck at first.", task: "Get one loud, real finger-whistle to come out. Even once.", encouragement: "You'll produce a lot of spit and air and no sound for a while. Everyone does. Adjust the tongue angle and keep going.", resources: r("The first ear-splitting success is a genuine 'I have a new power' moment.", "Learn to whistle a two-note taxi hail."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned to finger-whistle (loudly) 😗" }),
  C({ id: "MOV-110", skillId: "MOV", title: "Keep a hula hoop up for 30 seconds", level: "dabble", funnyResultsExpected: true, microLesson: "Hooping isn't circular hips — it's a front-to-back (or side-to-side) push against the hoop as it comes around. Give it a level, fast start and match its rhythm with small pushes.", task: "Keep a hula hoop spinning for 30 unbroken seconds.", needs: ["A hula hoop"], encouragement: "It'll hit the floor in two seconds repeatedly. Bigger, heavier hoops are easier — this is skill, not shame.", resources: r("Thirty seconds of steady hooping feels like a real reunion with childhood.", "Try walking while you hoop."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Kept the hula hoop up 🌀" }),
  C({ id: "LAN-110", skillId: "LAN", title: "Order your coffee entirely in a new language", level: "digin", together: true, microLesson: "A café order is a tiny fixed script: greeting, 'I'd like a ___,' 'for here/to go,' 'thank you.' Learn the four lines in one language and you can actually use it tomorrow.", task: "Learn the coffee-order script in a new language and use it for real (or role-play it convincingly).", encouragement: "You'll freeze and switch to English halfway. Totally normal — the barista's still charmed you tried.", resources: r("Pulling off a full order in another language feels great.", "Add 'keep the change' and a compliment."), budget: { time: "15m", cost: "cheap", setting: "errand" }, shareTemplate: "Ordered coffee in a new language ☕" }),
  C({ id: "CRA-110", skillId: "CRA", title: "Cut a six-fold paper snowflake", level: "dabble", together: true, microLesson: "Real snowflakes have six sides, so folding paper into SIXTHS (not fourths) before cutting makes a believable one. Fold, cut wedges from the edges, and the unfold is the reveal.", task: "Fold and cut two six-sided paper snowflakes. Unfold slowly for the surprise.", needs: ["Paper + scissors"], encouragement: "Cut too much and the center falls out — you made a doily. Still pretty. Try smaller cuts.", resources: r("The unfold is a tiny gift every single time.", "String several into a garland."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Cut paper snowflakes ❄️" }),
  C({ id: "GAM-110", skillId: "GAM", title: "Solve a set of five riddles", level: "dabble", together: true, microLesson: "Riddles hinge on a word doing double duty or a hidden literal reading. When stuck, question your assumptions — the 'obvious' meaning is usually the trap.", task: "Work through five classic riddles (no immediate googling). Time yourselves.", encouragement: "You'll want to peek within thirty seconds. Sit in the stuck-ness — the 'ohhh' is worth the wait.", resources: r("The groan when you finally get one is the whole point.", "Trade riddles you each know."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Riddle night 🧠" }),
  C({ id: "NAT-110", skillId: "NAT", title: "Do static-electricity tricks", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "Rubbing a balloon on hair steals electrons, giving it a charge that attracts light things and repels itself. That's static: bend a water stream, stick a balloon to the wall, make hair stand up.", task: "Do three static tricks: bend tap water, stick a balloon to a wall, raise someone's hair.", needs: ["A balloon", "Dry hair or wool"], encouragement: "Humid day? It barely works — that's physics, not you. Dry air makes it dramatic.", resources: r("Bending a stream of water with a balloon looks like a magic power.", "Learn WHY (electrons) — it's a two-minute rabbit hole."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Did static-electricity tricks ⚡" }),
  C({ id: "OUT-110", skillId: "OUT", title: "Stargaze with a sky-map app", level: "dabble", together: true, microLesson: "Point a free sky-map app at the night sky and it labels every star, planet, and constellation in real time — turning a random field of dots into a named, navigable map.", task: "Go out, hold up a sky app, and identify three constellations and one planet.", needs: ["A free sky-map app", "A dark-ish sky"], encouragement: "Light pollution hides a lot. Even three named objects beats a sky you couldn't read at all.", resources: r("Realizing that bright 'star' is actually Jupiter never gets old.", "Go somewhere truly dark someday and look up."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Read the whole night sky tonight 🔭" }),
  C({ id: "MND-110", skillId: "MND", title: "Write a gratitude letter to one person", level: "dabble", microLesson: "Gratitude research found the biggest boost comes not from a list but from writing a full letter to ONE specific person about what they did — whether or not you ever send it.", task: "Write a real letter to someone thanking them specifically. Send it, or don't — the writing is the exercise.", encouragement: "It'll get emotional faster than you expect. That's the effect working, not a problem.", resources: r("People who deliver these in person describe it as one of the best moments of their year.", "Consider actually reading it to them."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Wrote a gratitude letter 💛" }),
  C({ id: "SOC-110", skillId: "SOC", title: "Do one anonymous act of kindness", level: "dabble", microLesson: "Anonymous giving removes the thank-you reward, which is exactly what makes it feel clean and quietly good. Pay for a stranger's coffee, leave quarters at a laundromat, hide a kind note.", task: "Do one kind thing today where the person will never know it was you.", encouragement: "You won't get thanked — that's the design. The warm feeling is the entire payment.", resources: r("Anonymous kindness is a strangely durable mood-lifter.", "Make it a monthly ritual."), budget: { time: "15m", cost: "cheap", setting: "errand" }, shareTemplate: "Did a secret good deed today 🤍" }),
  C({ id: "STY-110", skillId: "STY", title: "Learn to fold a pocket square", level: "dabble", together: true, microLesson: "The presidential fold is a flat rectangle for formal; the puff is a scrunch for playful. Both take fifteen seconds once you know them, and instantly upgrade a jacket.", task: "Learn two pocket-square folds and set one in a jacket (or a friend's).", needs: ["A pocket square or any cloth"], encouragement: "The puff will look like a crumpled tissue at first. A little shaping and it reads intentional.", resources: r("A crisp pocket square is a huge upgrade for tiny effort.", "Learn the two-point fold next."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned to fold a pocket square 🤵" }),
  C({ id: "MAG-110", skillId: "MAG", title: "The classic coin-behind-the-ear", level: "dabble", together: true, funnyResultsExpected: true, microLesson: "The whole trick is a palm-and-produce: the coin hides against your fingers as your hand approaches the ear, then you 'find' it. Misdirection — look at the ear, they look at the ear.", task: "Produce a coin from behind someone's ear convincingly. Practice the palm in a mirror first.", needs: ["A coin"], encouragement: "The coin will clatter to the floor mid-reveal at least once. 'Ah, it was TRYING to escape.' Recover and repeat.", resources: r("A clean ear-coin makes any kid (or adult) gasp.", "Learn to 'vanish' it again afterward."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Pulled a coin from behind an ear 🪙" }),
  C({ id: "GRW-110", skillId: "GRW", title: "Make a kokedama moss ball", level: "digin", together: true, microLesson: "Kokedama is the Japanese 'moss ball' — a plant's roots wrapped in a ball of soil, bound in moss and string. It's bonsai's relaxed cousin: living sculpture you can hang or set on a dish.", task: "Wrap a small plant's root ball in soil and moss, bound with string, into a hanging ball.", needs: ["A small plant + moss + string + soil"], encouragement: "Your ball will be lumpy and shed soil. Lumpy is the aesthetic; wrap more string.", resources: r("A hanging moss ball with a plant sprouting from it looks like living art.", "Learn its soak-to-water routine."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Made a kokedama moss ball 🌿" }),

  // ===== EXTRA DOZEN =====
  C({ id: "CUL-112", skillId: "CUL", title: "Make fresh salsa from scratch", level: "dabble", together: true, microLesson: "Fresh (pico-style) salsa is just balance: tomato, onion, chili, lime, cilantro, salt — chopped, not blended, and rested ten minutes so the flavors marry. Roasting the tomato first adds smoke.", task: "Chop and mix a bowl of fresh salsa, rest it, then taste-and-adjust. Chips required.", needs: ["Tomato, onion, lime, chili"], encouragement: "First batch might be watery or flat — drain it and add salt/lime. Now you know the levers.", resources: r("Fresh salsa embarrasses the jarred stuff instantly.", "Try a charred-tomato or mango version."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made salsa from scratch 🍅" }),
  C({ id: "PHO-111", skillId: "PHO", title: "Make blackout poetry", level: "dabble", microLesson: "Blackout poetry finds a poem hiding in existing text: circle words you like on a page of newsprint, then black out everything else. The constraint of what's there sparks the art.", task: "Take any printed page and black out all but a scattered poem. Read it aloud.", needs: ["A printed page + a marker"], encouragement: "Your first pass keeps too many words and rambles. Cut harder — the gaps do the work.", resources: r("A found poem in a junk-mail page can be weirdly beautiful.", "Add a small doodle around the words."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Made blackout poetry 🖊️" }),
  C({ id: "MOV-111", skillId: "MOV", title: "Learn the robot dance", level: "dabble", funnyResultsExpected: true, microLesson: "The robot sells on 'hits' and stops: move one joint at a time, snap to a hard stop, hold dead still, then move the next. Smoothness is the enemy — jerky and rigid is the point.", task: "Do a 15-second robot routine with clean stops. Film one take.", encouragement: "You'll go too smooth and look like you're just... moving. Add hard stops between every motion.", resources: r("A committed robot with crisp stops genuinely reads.", "Add the 'malfunction' glitch ending."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Learned the robot 🤖" }),
  C({ id: "LAN-111", skillId: "LAN", title: "Learn to say a full toast in another language", level: "dabble", together: true, microLesson: "Toasts are short, warm, and universal — 'to health, to us, to tonight.' Learn one language's toast plus the clink word ('salud,' 'kanpai,' 'skål') and you've got a moment ready.", task: "Learn a short toast in a new language and deliver it before a drink or meal.", encouragement: "You'll mangle a word and laugh mid-toast. A fumbled heartfelt toast still lands.", resources: r("A toast in the language of the food you're eating is a lovely touch.", "Learn the eye-contact custom that goes with it."), budget: { time: "2m", cost: "free", setting: "home" }, shareTemplate: "Learned a toast in another language 🥂" }),
  C({ id: "CRA-111", skillId: "CRA", title: "Make a beaded bracelet", level: "dabble", together: true, microLesson: "Stretch cord + beads is the beginner's dream: no clasp, just thread a pattern, stretch, and double-knot with a dab of glue. The design is all in the bead sequence you plan first.", task: "String and knot one beaded bracelet with a deliberate pattern.", needs: ["Beads + stretch cord"], encouragement: "Beads will escape and roll under furniture. Losing a few beads is the tax; the bracelet still wins.", resources: r("A bracelet you designed and wear (or gift) is quietly satisfying.", "Try a word spelled in letter beads."), budget: { time: "15m", cost: "cheap", setting: "home" }, shareTemplate: "Made a beaded bracelet 📿" }),
  C({ id: "GAM-111", skillId: "GAM", title: "Play the perfect tic-tac-toe", level: "dabble", together: true, microLesson: "Tic-tac-toe is solved: open in a corner, and if you never miss a block or a double-threat ('fork'), you can never lose. Learn the fork and you'll force draws or wins forever.", task: "Learn the never-lose strategy, then play five rounds proving you can't be beaten.", needs: ["Paper + pen"], encouragement: "You'll miss a fork and lose once while learning. That loss teaches the exact pattern to watch.", resources: r("Being genuinely unbeatable at a 'kids' game is a fun flex.", "Teach the fork to someone else."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Became unbeatable at tic-tac-toe ⭕" }),
  C({ id: "NAT-111", skillId: "NAT", title: "Fold and fly a paper 'helicopter'", level: "dabble", together: true, microLesson: "A paper whirligig spins because two bent flaps catch air unevenly as it falls, creating lift on one side — the same autorotation that lets real helicopters land engine-off.", task: "Fold a paper whirligig, drop it from up high, and watch it autorotate. Race two.", needs: ["Paper + scissors + a paperclip"], encouragement: "It'll just plummet if the flaps are even — bend them opposite ways and add a clip for weight.", resources: r("A well-folded whirligig spins down like a maple seed.", "Learn WHY maple seeds do the same thing."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Made a paper helicopter fly 🚁" }),
  C({ id: "MND-111", skillId: "MND", title: "Eat one meal with zero screens", level: "dabble", together: true, microLesson: "Single-tasking a meal — no phone, no show, just the food and maybe a person — is a small mindfulness rep. You taste more, eat slower, and the meal actually registers as an event.", task: "Eat one full meal today with every screen off and away. Notice the food.", encouragement: "Your hand will reach for your phone on reflex. Put it in another room to remove the choice.", resources: r("A phone-free meal feels weirdly long and calm — in a good way.", "Make it a nightly ritual."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Ate a whole meal screen-free 🍽️" }),
  C({ id: "STY-111", skillId: "STY", title: "Build a five-piece capsule outfit", level: "dabble", microLesson: "A capsule is a few pieces that all mix: pick items that share a palette so any top works with any bottom. Five well-chosen pieces can make a week of outfits.", task: "Pull five items from your closet that all combine, and lay out three different outfits from them.", encouragement: "You'll find two 'orphan' pieces that go with nothing you own. Useful to know — that's why you had nothing to wear.", resources: r("Realizing five pieces make a week of looks is genuinely freeing.", "Pack ONLY a capsule for your next trip."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Built a capsule wardrobe 👗" }),
  C({ id: "SOC-111", skillId: "SOC", title: "Host a two-person game night", level: "dabble", together: true, microLesson: "Two-player game nights just need one good pick and no phones: a card game, a quick board game, or a stack of 'would you rather.' The ritual (snacks, no screens) matters more than the game.", task: "Set up snacks, pick two games, and play a proper no-phones game night.", needs: ["A game or two + snacks"], encouragement: "One game will fall flat or spark mild competitive rage. Both are correct game-night outcomes.", resources: r("A recurring two-person game night is a quietly great tradition.", "Keep a running championship scoreboard."), budget: { time: "1h", cost: "cheap", setting: "home" }, shareTemplate: "Hosted a game night 🎲" }),
  C({ id: "WRI-110", skillId: "WRI", title: "Write an acrostic of someone's name", level: "dabble", together: true, microLesson: "An acrostic spells a word down the first letters of each line. For a name, each line says something true about the person — constraint plus affection makes it land.", task: "Write an acrostic poem using someone's name, one honest/funny line per letter.", encouragement: "The letter 'X' or 'Q' will stump you. Cheating creatively around it is half the fun.", resources: r("A name acrostic is a five-minute gift people keep.", "Frame it or text it as a surprise."), budget: { time: "15m", cost: "free", setting: "home" }, shareTemplate: "Wrote an acrostic poem 🔤" }),
  C({ id: "OUT-111", skillId: "OUT", title: "Cloud-watch and find three shapes", level: "dabble", together: true, microLesson: "Pareidolia is your brain's habit of finding faces and animals in random shapes — clouds are the classic playground. Lying back and naming shapes is a real, ancient form of rest.", task: "Lie back for fifteen minutes and find at least three distinct shapes in the clouds together.", encouragement: "Clear sky? Reschedule guilt-free — you can't cloud-watch an empty blue. Overcast is perfect.", resources: r("Fifteen minutes of cloud-watching is more restorative than it has any right to be.", "Do it after the sunrise/sunset one."), budget: { time: "15m", cost: "free", setting: "outdoors" }, shareTemplate: "Spent fifteen minutes cloud-watching ☁️" }),
];
